import type OlMap from "ol/Map.js";
import type BaseLayer from "ol/layer/Base.js";
import { unByKey } from "ol/Observable.js";
import type { EventsKey } from "ol/events.js";
import { toLonLat, fromLonLat } from "ol/proj.js";

import {
  Cartesian2,
  Cartesian3,
  Ellipsoid,
  Math as CesiumMath,
  ScreenSpaceEventHandler,
  ScreenSpaceEventType,
  SceneTransforms,
  defined,
  Viewer,
  createWorldTerrainAsync,
} from "cesium";

import {
  convertLayerToCesium,
  syncVisibility,
  type ConvertedResult,
} from "../utils/layerConverters";
import {
  olResolutionToCesiumHeightMeters,
  cesiumHeightMetersToOlResolution,
} from "../utils/cameraMath";

import type {
  CameraSyncOptions,
  InteractionSyncOptions,
  LayerMapping,
  VectorOptions,
  ViewState,
} from "../types/adapter";

export type OlCesiumOptions = {
  map: OlMap;
  target: HTMLElement | string;
  enabled?: boolean;
  enableTerrain?: boolean;
  /**
   * If true, removing 3D mode will also remove converted Cesium layers/dataSources.
   * Defaults to false to preserve state across enable/disable (closer to ol-cesium behavior).
   */
  clearOnDisable?: boolean;
  cameraSyncOptions?: CameraSyncOptions;
  vectorOptions?: VectorOptions;
  interactionSync?: boolean | InteractionSyncOptions;
  autoOrderLayers?: boolean;
  overlaySync?: boolean;
  onCameraChange?: (vs: ViewState) => void;
};

export class OlCesium {
  private map: OlMap;
  private viewer: Viewer;
  private enabled = false;
  private clearOnDisable: boolean;

  private cameraSyncOptions: CameraSyncOptions;
  private vectorOptions: VectorOptions;
  private interactionSync: boolean | InteractionSyncOptions;
  private autoOrderLayers: boolean;
  private overlaySync: boolean;
  private onCameraChange?: (vs: ViewState) => void;

  private syncing: "ol" | "cesium" | null = null;
  private syncTimer: ReturnType<typeof setTimeout> | null = null;
  private rafOlToCesium: number | null = null;
  private rafCesiumToOl: number | null = null;
  private lastCesiumToOlTs = 0;
  private lastApplied: {
    lon: number;
    lat: number;
    zoom: number;
    rotation: number;
  } | null = null;

  private layerMappings: LayerMapping[] = [];
  private layerKeys = new WeakMap<any, EventsKey[]>();
  private sourceKeys = new WeakMap<any, EventsKey[]>();
  private vectorRefreshTimers = new WeakMap<
    any,
    ReturnType<typeof setTimeout>
  >();

  private viewKeys: EventsKey[] = [];
  private layersCollectionKeys: EventsKey[] = [];
  private cameraChangedRemove: (() => void) | null = null;
  private overlayPostRenderRemove: (() => void) | null = null;
  private interactionHandler: ScreenSpaceEventHandler | null = null;

  constructor(options: OlCesiumOptions) {
    this.map = options.map;
    this.cameraSyncOptions = options.cameraSyncOptions ?? {};
    this.vectorOptions = options.vectorOptions ?? {};
    this.interactionSync = options.interactionSync ?? false;
    this.autoOrderLayers = options.autoOrderLayers ?? true;
    this.overlaySync = options.overlaySync ?? true;
    this.onCameraChange = options.onCameraChange;
    this.clearOnDisable = options.clearOnDisable ?? false;

    const target =
      typeof options.target === "string"
        ? (document.getElementById(options.target) as HTMLElement | null)
        : options.target;
    if (!target) {
      throw new Error("OlCesium: target element not found");
    }

    this.viewer = new Viewer(target, {
      animation: false,
      baseLayerPicker: false,
      fullscreenButton: false,
      geocoder: false,
      homeButton: false,
      infoBox: false,
      sceneModePicker: false,
      selectionIndicator: false,
      timeline: false,
      navigationHelpButton: false,
      navigationInstructionsInitiallyVisible: false,
      scene3DOnly: true,
    });

    // Clear default imagery. We drive imagery from OL layers.
    this.viewer.imageryLayers.removeAll();

    // Reasonable defaults for perf and visuals
    this.viewer.scene.globe.enableLighting = false;
    this.viewer.scene.fog.enabled = false;
    if (this.viewer.scene.skyAtmosphere) {
      this.viewer.scene.skyAtmosphere.show = true;
    }
    this.viewer.scene.globe.showGroundAtmosphere = true;

    if (options.enableTerrain) {
      createWorldTerrainAsync().then((terrain) => {
        if (!this.viewer.isDestroyed()) {
          this.viewer.terrainProvider = terrain;
        }
      });
    }

    this.setEnabled(options.enabled ?? true);
  }

  getOlMap(): OlMap {
    return this.map;
  }

  getCesiumViewer(): Viewer {
    return this.viewer;
  }

  isEnabled(): boolean {
    return this.enabled;
  }

  setTarget(target: HTMLElement | string) {
    const el =
      typeof target === "string"
        ? (document.getElementById(target) as HTMLElement | null)
        : target;
    if (!el) throw new Error("OlCesium: target element not found");
    // Cesium Viewer does not allow changing `container` after creation.
    // Move the existing container DOM node instead.
    el.appendChild(this.viewer.container);
    this.viewer.resize();
    this.viewer.scene.requestRender();
  }

  setEnabled(enabled: boolean) {
    if (this.enabled === enabled) return;
    this.enabled = enabled;

    const container = this.viewer.container as HTMLElement | undefined;
    if (container) {
      container.style.visibility = enabled ? "visible" : "hidden";
      container.style.pointerEvents = enabled ? "auto" : "none";
    }

    if (enabled) {
      this.attach();
      this.syncOnce();
    } else {
      this.detach();
      if (this.clearOnDisable) {
        this.clearCesiumLayers();
      }
    }
  }

  syncOnce() {
    if (!this.enabled) return;
    this.syncOlToCesium();
    this.syncLayers();
    this.viewer.scene.requestRender();
  }

  destroy() {
    this.detach();
    this.clearCesiumLayers();
    if (!this.viewer.isDestroyed()) {
      this.viewer.destroy();
    }
  }

  private attach() {
    // View change -> Cesium
    const view = this.map.getView();
    this.viewKeys = [
      view.on("change:center", () => this.scheduleOlToCesium()),
      view.on("change:resolution", () => this.scheduleOlToCesium()),
      view.on("change:rotation", () => this.scheduleOlToCesium()),
    ];

    // Cesium camera -> OL
    this.viewer.camera.percentageChanged = 0.01;
    this.cameraChangedRemove = this.viewer.camera.changed.addEventListener(() =>
      this.scheduleCesiumToOl(),
    );

    // Layer collection changes
    const layers = this.map.getLayers();
    const onAdd = (event: any) => this.addLayerToCesium(event.element);
    const onRemove = (event: any) => this.removeLayerFromCesium(event.element);
    this.layersCollectionKeys = [
      layers.on("add", onAdd),
      layers.on("remove", onRemove),
    ];

    // Interaction sync
    if (this.interactionSync) {
      const opts: InteractionSyncOptions =
        typeof this.interactionSync === "boolean"
          ? { click: true, hover: true, select: true }
          : this.interactionSync;

      this.interactionHandler = new ScreenSpaceEventHandler(
        this.viewer.scene.canvas,
      );

      if (opts.click) {
        this.interactionHandler.setInputAction(
          (movement: { position: { x: number; y: number } }) => {
            const pick = this.viewer.scene.pick(
              new Cartesian2(movement.position.x, movement.position.y),
            );
            if (defined(pick) && (pick as any).id) {
              const cart = this.viewer.scene.globe.pick(
                this.viewer.camera.getPickRay(
                  new Cartesian2(movement.position.x, movement.position.y),
                )!,
                this.viewer.scene,
              );
              if (cart) {
                const cartographic =
                  Ellipsoid.WGS84.cartesianToCartographic(cart);
                const lon = CesiumMath.toDegrees(cartographic.longitude);
                const lat = CesiumMath.toDegrees(cartographic.latitude);
                this.map.dispatchEvent({
                  type: "cesium:click",
                  coordinate: fromLonLat([lon, lat]),
                  entity: (pick as any).id,
                } as any);
              }
            }
          },
          ScreenSpaceEventType.LEFT_CLICK,
        );
      }

      if (opts.hover) {
        this.interactionHandler.setInputAction(
          (movement: { endPosition: { x: number; y: number } }) => {
            const pick = this.viewer.scene.pick(
              new Cartesian2(movement.endPosition.x, movement.endPosition.y),
            );
            this.map.dispatchEvent({
              type: "cesium:hover",
              entity: defined(pick) ? (pick as any).id : null,
            } as any);
          },
          ScreenSpaceEventType.MOUSE_MOVE,
        );
      }
    }

    // Overlay sync
    if (this.overlaySync) {
      this.overlayPostRenderRemove =
        this.viewer.scene.postRender.addEventListener(() =>
          this.syncOverlays(),
        );
    }
  }

  private detach() {
    if (this.viewKeys.length) {
      unByKey(this.viewKeys);
      this.viewKeys = [];
    }
    if (this.layersCollectionKeys.length) {
      unByKey(this.layersCollectionKeys);
      this.layersCollectionKeys = [];
    }
    if (this.cameraChangedRemove) {
      this.cameraChangedRemove();
      this.cameraChangedRemove = null;
    }
    if (this.overlayPostRenderRemove) {
      this.overlayPostRenderRemove();
      this.overlayPostRenderRemove = null;
    }
    if (this.interactionHandler) {
      this.interactionHandler.destroy();
      this.interactionHandler = null;
    }
    if (this.rafOlToCesium != null) {
      cancelAnimationFrame(this.rafOlToCesium);
      this.rafOlToCesium = null;
    }
    if (this.rafCesiumToOl != null) {
      cancelAnimationFrame(this.rafCesiumToOl);
      this.rafCesiumToOl = null;
    }

    // Per-layer/source listeners
    for (const mapping of this.layerMappings) {
      this.cleanupLayerListeners(mapping.olLayer as any);
    }
  }

  private clearCesiumLayers() {
    // Remove converted layers/dataSources
    for (const mapping of this.layerMappings) {
      this.removeCesiumObject(mapping);
    }
    this.layerMappings = [];
    this.viewer.imageryLayers.removeAll();
    this.viewer.dataSources.removeAll();
  }

  private scheduleOlToCesium() {
    if (!this.enabled) return;
    if (this.rafOlToCesium != null) return;
    this.rafOlToCesium = requestAnimationFrame(() => {
      this.rafOlToCesium = null;
      this.syncOlToCesium();
    });
  }

  private scheduleCesiumToOl() {
    if (!this.enabled) return;
    const now =
      typeof performance !== "undefined" ? performance.now() : Date.now();
    if (now - this.lastCesiumToOlTs < 33) return;
    this.lastCesiumToOlTs = now;

    if (this.rafCesiumToOl != null) return;
    this.rafCesiumToOl = requestAnimationFrame(() => {
      this.rafCesiumToOl = null;
      this.syncCesiumToOl();
    });
  }

  private syncOlToCesium() {
    if (!this.enabled || this.syncing === "cesium") return;

    const view = this.map.getView();
    const center = view.getCenter();
    if (!center) return;

    const {
      animate = true,
      animationDuration = 0.5,
      debounceMs = 100,
    } = this.cameraSyncOptions;

    const [lon, lat] = toLonLat(center, view.getProjection());
    const zoom = view.getZoom() ?? 2;
    const rotation = -(view.getRotation() ?? 0);

    const resolution =
      view.getResolution() ??
      (typeof (view as any).getResolutionForZoom === "function"
        ? (view as any).getResolutionForZoom(zoom)
        : undefined) ??
      20_000_000 / Math.pow(2, zoom - 1);
    const isWebMercator = view.getProjection()?.getCode?.() === "EPSG:3857";
    const height = olResolutionToCesiumHeightMeters({
      resolution,
      latDeg: lat,
      olSize: this.map.getSize() ?? undefined,
      viewer: this.viewer,
      isWebMercator,
    });
    const destination = Cartesian3.fromDegrees(lon, lat, height);

    const useInstantSync = !animate || this.syncing === "ol";
    const orientation = {
      heading: rotation,
      pitch: this.viewer.camera.pitch,
      roll: this.viewer.camera.roll,
    };

    if (!useInstantSync) {
      this.viewer.camera.flyTo({
        destination,
        orientation,
        duration: animationDuration,
      });
    } else {
      this.viewer.camera.cancelFlight();
      this.viewer.camera.setView({ destination, orientation });
    }

    this.syncing = "ol";

    this.onCameraChange?.({
      center: [lon, lat],
      zoom,
      rotation: view.getRotation() ?? 0,
      tilt: 0,
    });

    if (this.syncTimer) clearTimeout(this.syncTimer);
    this.syncTimer = setTimeout(() => {
      this.syncing = null;
    }, debounceMs);
  }

  private syncCesiumToOl() {
    if (!this.enabled || this.syncing === "ol") return;

    const camera = this.viewer.camera;
    const carto = Ellipsoid.WGS84.cartesianToCartographic(camera.position);
    if (!carto) return;

    const { debounceMs = 100 } = this.cameraSyncOptions;

    this.syncing = "cesium";

    const lon = CesiumMath.toDegrees(carto.longitude);
    const lat = CesiumMath.toDegrees(carto.latitude);
    const height = carto.height;
    const rotation = -camera.heading;

    const view = this.map.getView();
    const isWebMercator = view.getProjection()?.getCode?.() === "EPSG:3857";
    const resolution = cesiumHeightMetersToOlResolution({
      heightMeters: height,
      latDeg: lat,
      olSize: this.map.getSize() ?? undefined,
      viewer: this.viewer,
      isWebMercator,
    });
    const zoom =
      typeof (view as any).getZoomForResolution === "function"
        ? (view as any).getZoomForResolution(resolution)
        : Math.log2(20_000_000 / Math.max(height, 1)) + 1;

    const clampedZoom = Math.max(0, Math.min(28, zoom));
    const prev = this.lastApplied;
    const shouldUpdate =
      !prev ||
      Math.abs(prev.lon - lon) > 1e-7 ||
      Math.abs(prev.lat - lat) > 1e-7 ||
      Math.abs(prev.zoom - clampedZoom) > 0.02 ||
      Math.abs(prev.rotation - rotation) > 1e-4;

    if (shouldUpdate) {
      view.setCenter(fromLonLat([lon, lat], view.getProjection()));
      if (!prev || Math.abs(prev.zoom - clampedZoom) > 0.02) {
        view.setZoom(clampedZoom);
      }
      if (!prev || Math.abs(prev.rotation - rotation) > 1e-4) {
        view.setRotation(rotation);
      }
      this.lastApplied = { lon, lat, zoom: clampedZoom, rotation };
    }

    const tilt = CesiumMath.toDegrees(camera.pitch) + 90;
    this.onCameraChange?.({
      center: [lon, lat],
      zoom,
      rotation: -rotation,
      tilt,
    });

    if (this.syncTimer) clearTimeout(this.syncTimer);
    this.syncTimer = setTimeout(() => {
      this.syncing = null;
    }, debounceMs);
  }

  private syncLayers() {
    if (!this.enabled) return;
    const layers = this.map.getLayers().getArray();

    // Remove mappings for layers no longer present
    const remaining: LayerMapping[] = [];
    for (const mapping of this.layerMappings) {
      if (layers.includes(mapping.olLayer)) {
        remaining.push(mapping);
      } else {
        this.removeCesiumObject(mapping);
        this.cleanupLayerListeners(mapping.olLayer as any);
      }
    }
    this.layerMappings = remaining;

    // Add missing layers
    for (const olLayer of layers) {
      if (!this.layerMappings.find((m) => m.olLayer === olLayer)) {
        this.addLayerToCesium(olLayer);
      }
    }

    if (this.autoOrderLayers) {
      this.applyDefaultZIndex();
    }
    this.updateCesiumZOrder();
  }

  private addLayerToCesium(olLayer: BaseLayer) {
    if (!this.enabled) return;
    const view = this.map.getView();
    const resolvedVectorOpts: VectorOptions = {
      ...this.vectorOptions,
      resolution: view.getResolution() ?? this.vectorOptions.resolution ?? 1,
      extent: this.vectorOptions.extent ?? view.calculateExtent(),
    };

    const result = convertLayerToCesium(olLayer, resolvedVectorOpts);
    if (!result) return;

    const mapping: LayerMapping = {
      olLayer,
      cesiumLayer: result.imagery || result.dataSource || null,
      type: result.type,
      visible: (olLayer as any).getVisible?.() ?? true,
      opacity: (olLayer as any).getOpacity?.() ?? 1,
    };

    if (result.type === "imagery" && result.imagery) {
      this.viewer.imageryLayers.add(result.imagery);
    } else if (result.type === "vector" && result.dataSource) {
      this.viewer.dataSources.add(result.dataSource);
    }

    this.layerMappings.push(mapping);
    this.attachLayerListeners(olLayer);
    if (result.type === "vector") {
      this.attachSourceListeners(olLayer);
    }
    this.updateCesiumZOrder();
    this.viewer.scene.requestRender();
  }

  private removeLayerFromCesium(olLayer: BaseLayer) {
    const mapping = this.layerMappings.find((m) => m.olLayer === olLayer);
    if (!mapping) return;
    this.removeCesiumObject(mapping);
    this.cleanupLayerListeners(olLayer as any);
    this.layerMappings = this.layerMappings.filter((m) => m !== mapping);
    this.viewer.scene.requestRender();
  }

  private removeCesiumObject(mapping: LayerMapping) {
    if (!mapping.cesiumLayer) return;
    try {
      if (mapping.type === "imagery") {
        this.viewer.imageryLayers.remove(mapping.cesiumLayer as any, true);
      } else if (mapping.type === "vector") {
        this.viewer.dataSources.remove(mapping.cesiumLayer as any, true);
      }
    } catch {
      // ignore
    }
  }

  private attachLayerListeners(layer: any) {
    if (!layer || typeof layer.on !== "function") return;
    if (this.layerKeys.has(layer)) return;

    const onVis = () => {
      const mapping = this.layerMappings.find((m) => m.olLayer === layer);
      if (mapping) syncVisibility(layer, mapping);
      this.viewer.scene.requestRender();
    };
    const onOpacity = () => {
      const mapping = this.layerMappings.find((m) => m.olLayer === layer);
      if (mapping) syncVisibility(layer, mapping);
      this.viewer.scene.requestRender();
    };
    const onZ = () => {
      this.updateCesiumZOrder();
      this.viewer.scene.requestRender();
    };

    const keys: EventsKey[] = [
      layer.on("change:visible", onVis),
      layer.on("change:opacity", onOpacity),
      layer.on("change:zIndex", onZ),
    ];
    this.layerKeys.set(layer, keys);
  }

  private attachSourceListeners(layer: any) {
    const source = layer?.getSource?.();
    if (!source || typeof source.on !== "function") return;
    if (this.sourceKeys.has(source)) return;

    const scheduleRefresh = () => {
      const existing = this.vectorRefreshTimers.get(layer);
      if (existing) clearTimeout(existing);

      const timer = setTimeout(() => {
        if (!this.enabled) return;
        const mapping = this.layerMappings.find((m) => m.olLayer === layer);
        if (!mapping || mapping.type !== "vector") return;

        try {
          this.viewer.dataSources.remove(mapping.cesiumLayer as any, true);
        } catch {
          // ignore
        }

        const view = this.map.getView();
        const resolvedVectorOpts: VectorOptions = {
          ...this.vectorOptions,
          resolution:
            view.getResolution() ?? this.vectorOptions.resolution ?? 1,
          extent: this.vectorOptions.extent ?? view.calculateExtent(),
        };
        const result = convertLayerToCesium(layer, resolvedVectorOpts);
        if (result && result.dataSource) {
          this.viewer.dataSources.add(result.dataSource);
          mapping.cesiumLayer = result.dataSource;
          this.updateCesiumZOrder();
          this.viewer.scene.requestRender();
        }
      }, 100);

      this.vectorRefreshTimers.set(layer, timer);
    };

    const keys: EventsKey[] = [
      source.on("addfeature", scheduleRefresh),
      source.on("removefeature", scheduleRefresh),
      source.on("clear", scheduleRefresh),
    ];
    this.sourceKeys.set(source, keys);
  }

  private cleanupLayerListeners(layer: any) {
    const layerKeys = this.layerKeys.get(layer);
    if (layerKeys) {
      unByKey(layerKeys);
      this.layerKeys.delete(layer);
    }

    const source = layer?.getSource?.();
    if (source) {
      const sourceKeys = this.sourceKeys.get(source);
      if (sourceKeys) {
        unByKey(sourceKeys);
        this.sourceKeys.delete(source);
      }
    }

    const timer = this.vectorRefreshTimers.get(layer);
    if (timer) {
      clearTimeout(timer);
      this.vectorRefreshTimers.delete(layer);
    }
  }

  private updateCesiumZOrder() {
    const olLayers = this.map.getLayers().getArray();

    const imageryMappings = this.layerMappings
      .filter((m) => m.type === "imagery" && m.cesiumLayer)
      .sort((a, b) => {
        const zA = (a.olLayer as any).getZIndex?.() || 0;
        const zB = (b.olLayer as any).getZIndex?.() || 0;
        if (zA !== zB) return zA - zB;
        return olLayers.indexOf(a.olLayer) - olLayers.indexOf(b.olLayer);
      });
    imageryMappings.forEach((m) => {
      this.viewer.imageryLayers.raiseToTop(m.cesiumLayer as any);
    });

    const vectorMappings = this.layerMappings
      .filter((m) => m.type === "vector" && m.cesiumLayer)
      .sort((a, b) => {
        const zA = (a.olLayer as any).getZIndex?.() || 0;
        const zB = (b.olLayer as any).getZIndex?.() || 0;
        if (zA !== zB) return zA - zB;
        return olLayers.indexOf(a.olLayer) - olLayers.indexOf(b.olLayer);
      });
    vectorMappings.forEach((m) => {
      try {
        this.viewer.dataSources.raiseToTop(m.cesiumLayer as any);
      } catch {
        // ignore
      }
    });
  }

  private applyDefaultZIndex() {
    // Mimic the hook behavior: base=0, wms=10, vector=20 (unless user sets zIndex > 0)
    for (const layer of this.map.getLayers().getArray() as any[]) {
      if (!layer || typeof layer.getZIndex !== "function") continue;
      if (layer.getZIndex() > 0) continue;

      const source = layer.getSource?.();
      const isTile = layer?.constructor?.name?.includes?.("Tile") ?? false;
      const isVector = layer?.constructor?.name?.includes?.("Vector") ?? false;
      const isWms = source?.constructor?.name?.includes?.("WMS") ?? false;

      if (isTile && !isWms) layer.setZIndex(0);
      else if (isWms) layer.setZIndex(10);
      else if (isVector) layer.setZIndex(20);
    }
  }

  private syncOverlays() {
    if (!this.enabled) return;
    const overlays = this.map.getOverlays().getArray();
    const scene = this.viewer.scene;
    const camera = this.viewer.camera;
    const view = this.map.getView();

    for (const overlay of overlays) {
      const element = overlay.getElement();
      if (!element) continue;

      const position = overlay.getPosition();
      if (!position) {
        (element as HTMLElement).style.display = "none";
        continue;
      }

      const [lon, lat] = toLonLat(position, view.getProjection());
      const cartesian = Cartesian3.fromDegrees(lon, lat);
      const canvasCoord = SceneTransforms.worldToWindowCoordinates(
        scene,
        cartesian,
      );

      if (!canvasCoord) {
        (element as HTMLElement).style.display = "none";
        continue;
      }

      // Hide if behind the camera
      const cameraToPos = Cartesian3.subtract(
        cartesian,
        camera.position,
        new Cartesian3(),
      );
      const dot = Cartesian3.dot(cameraToPos, camera.direction);
      if (dot <= 0) {
        (element as HTMLElement).style.display = "none";
        continue;
      }

      const el = element as HTMLElement;
      el.style.display = "block";
      el.style.position = "absolute";
      el.style.left = `${canvasCoord.x}px`;
      el.style.top = `${canvasCoord.y}px`;
      el.style.transform = "translate(-50%, -100%)";
      el.style.pointerEvents = "auto";
    }
  }
}
